var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"흠...... 이 사람이 그 기술자인가?","JPN":"ふむ……彼が例のエンジニアか？","ENG":"Hmm... Is this the engineer you spoke of?","TWN":"呃……這個人就是那個技術人員？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너무 젊군. 믿음이 가질 않아.","JPN":"若すぎるな。果たして信用していいものか……","ENG":"Too young. Way too young to earn my trust.","TWN":"太年輕了，我信不過。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"처음 보는 사이에 너무하는군.","JPN":"初対面なのに遠慮がなさすぎるぞ。","ENG":"Well, that's a bit rude considering this is our first time meeting.","TWN":"對初次見面的人，這話說得還真是過分呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정할 필요 없어. 구 관리국의 낡은 보안 시스템 정도는 눈 감고도 해제할 수 있으니까.","JPN":"安心したまえ。旧管理局のカビの生えた\\nセキュリティなんぞは目を瞑ってでも解除できる。","ENG":"Don't worry though. I could disarm an outdated security system from the Old Administration with my eyes closed.","TWN":"不用擔心，舊管理局的老舊安全系統，就算我閉著眼睛也能解除。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"낡은 보안 시스템? 제대로 알긴 하는 건가?","JPN":"カビの生えたセキュリティ？　自分の言ってる意味がわかってるのか？","ENG":"Outdated security system? Do you even know what you're talking about?","TWN":"老舊安全系統？你確定你真的瞭解嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리국의 보안 시스템은 시대를 초월한 기술의 집약체다. 평범한 방법으론 접근조차 할 수 없어.","JPN":"管理局のセキュリティシステムは時代を超越した\\n技術の粋を集めて作られている。通常の方法ではアクセスすらままならぬ代物だ。","ENG":"The Administration's security system is the apex of all technologies beyond time. You won't be able to even access its codes through conventional means.","TWN":"管理局的安保系統是跨時代科技的集合體，一般的方法根本沒辦法連接。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래 봐야 몇 십 년 전에나 쓰던 기술 아닌가? 낡은 건 사실이지.","JPN":"所詮何十年も前に使われた技術だろ？\\nカビが生えているのは確かさ。","ENG":"So? It's still decades old, isn't it? It might be all fancy as you say, but it's still outdated.","TWN":"但不就是幾十年前的技術嘛，老舊是事實啊。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"너, 배짱은 두둑한 것 같다만......","JPN":"貴様、度胸だけは認めるが……","ENG":"While I applaud your confidence...","TWN":"你，口氣倒是挺大……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그만해, 류드밀라.","JPN":"よしなさい、リュドミラ。","ENG":"Enough, Lyudmila.","TWN":"夠了，盧德米拉。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"실력은 확실한 사람이야. 내가 보증하지.","JPN":"この人、腕の方は確かよ。私が保証するわ。","ENG":"This engineer has the skills we need. I can vouch for that.","TWN":"他確實是個有實力的人，這我可以保證。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......알겠다. 네가 그렇게 말한다면야.","JPN":"……わかった。君に免じて、ひとまず納得しておこう。","ENG":"Very well. If you say so.","TWN":"……好吧，既然妳都這麼說了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 본 기는 양자좌표석에서 분석된 좌표로 이동 중입니다.</color>","JPN":"<color=#ffd34c>現在、本機は量子座標石で分析された座標へ移動中です。</color>","ENG":"<color=#ffd34c>This ship is currently headed for the coordinates analyzed through the Quantum Coords Crystal.</color>","TWN":"<color=#ffd34c>本機正往量子座標石分析出的座標移動。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다이브 중 이동은 위험하오니, 탑승자 여러분은 안내 방송 전까지 자리에서 대기해 주십시오.</color>","JPN":"<color=#ffd34c>ダイブ中の移動は危険ですので、搭乗者の皆様はアナウンスがあるまでお席でお待ちください。</color>","ENG":"<color=#ffd34c>All passengers should remain seated until notified as it can be dangerous to move around the cabin during the dive.</color>","TWN":"<color=#ffd34c>在躍入中時移動會發生危險，請搭乘人員聽到廣播之前，坐在位子上待機。</color>"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"꽤 깐깐한 친구더군. 어린 시절 자네와 친했다는 게 믿기지 않아.","JPN":"彼女はなかなか気難しいタイプだな。\\nあれで幼い頃の君と親友だったとは信じがたい。","ENG":"She seems pretty stiff. I can't believe you used to be close when you were younger.","TWN":"真是位強硬的朋友呢，不敢相信她和妳以前很要好。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"처음부터 저런 성격은 아니었습니다.","JPN":"はじめからあんな性格ではなかったのです。","ENG":"She wasn't always like that.","TWN":"她一開始的個性不是這樣的。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저와 비슷한 시기에 관리국에 들어온 동기였는데...... 그때는 피만 보면 졸도하곤 했었죠.","JPN":"彼女は私と近い時期に管理局に入った同期ですが……\\nあの頃は、血を見ただけで卒倒していました。","ENG":"We joined the Administration around the same time... Back then, she'd pass out at the sight of blood.","TWN":"她和我同期進入管理局……那時候，她一見到血就會暈倒。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"피만 보면 졸도해? 그런 사람이 어떻게 전대장까지 올라온 거지?","JPN":"血を見ただけで卒倒？\\nそんな人間がどうやって戦隊長に登り詰めたんだ？","ENG":"She passed out at the sight of blood? How did someone like that ever make it to division commander?","TWN":"一見到血就會暈倒？那樣的人怎麼會晉升到戰隊隊長？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};